/**
 * Smoke test: specialist config loading + isLocalSpecialist.
 *
 * Run: node scripts/check-specialist.mjs
 */
import { mkdir, rm, writeFile } from "node:fs/promises";
import path from "node:path";

const TMP_ROOT = path.join(process.cwd(), "output", "tmp", `check-specialist-${process.pid}`);
const AGENT_CONFIG_DIR = path.join(TMP_ROOT, "agent-config");
const CONFIG_DIR = path.join(TMP_ROOT, "memory", "config");

let passed = 0;
let failed = 0;

function assert(cond, msg) {
  if (cond) { passed++; console.log(`  ✓ ${msg}`); }
  else { failed++; console.error(`  ✗ ${msg}`); }
}

async function main() {
  process.env.MEMORY_DIR = path.join(TMP_ROOT, "memory");
  process.env.ACP_SESSION_CWD = process.cwd();

  await mkdir(CONFIG_DIR, { recursive: true });
  await mkdir(AGENT_CONFIG_DIR, { recursive: true });
  await writeFile(path.join(CONFIG_DIR, "specialists.json"), JSON.stringify([
    {
      name: "slot-dev",
      harness: { command: "kiro-cli", args: ["acp", "--agent", "slot-dev"] },
      cwd: "${AGENT_CONFIG_DIR}\\workspace",
      env: { TEST_AGENT_HOME: "${AGENT_CONFIG_DIR}" },
    },
  ], null, 2), "utf8");

  const { loadSpecialistsConfig, isLocalSpecialist, getSpecialists } =
    await import("../dist/specialist.js");

  console.log("=== Specialist Config Loading ===");

  const count = await loadSpecialistsConfig(AGENT_CONFIG_DIR);
  assert(count >= 1, `loaded ${count} specialist(s) from config`);

  const specs = getSpecialists();
  assert(specs.length >= 1, `getSpecialists() returns ${specs.length} entries`);

  const slotDev = specs.find(s => s.name === "slot-dev");
  assert(!!slotDev, "slot-dev entry exists");
  assert(slotDev?.harness?.command === "kiro-cli", `harness command = "${slotDev?.harness?.command}"`);
  assert(slotDev?.cwd === path.join(AGENT_CONFIG_DIR, "workspace"), `cwd = "${slotDev?.cwd}"`);

