/**
 * Smoke test: Phase B+ Specialist Persistent Memory
 *
 * 驗證 extractLessons / appendMemory / readMemory / onSpecialistDone 端到端正確性。
 *
 * Run: node scripts/check-specialist-memory.mjs
 */
import { unlinkSync } from "node:fs";
import path from "node:path";

process.env.TELEGRAM_BOT_TOKEN ||= "dummy"; // config.ts requires it

const { extractLessons, appendMemory, readMemory, onSpecialistDone } =
  await import("../dist/specialist-memory.js");
const { config } = await import("../dist/config.js");

const TEST_NAME = "_smoke_test_";
const memFile = path.join(config.memoryDir, "specialist-memory", `${TEST_NAME}.md`);

let passed = 0;
let failed = 0;

function assert(cond, msg) {
  if (cond) { passed++; console.log(`  ✓ ${msg}`); }
  else { failed++; console.error(`  ✗ ${msg}`); }
}

// ─── cleanup helper ──────────────────────────────────────────────────────

function cleanup() {
  try { unlinkSync(memFile); } catch { /* ok if not exist */ }
}

// ═══════════════════════════════════════════════════════════════════════════
// Test 1: extractLessons — 有 artifact JSON
// ═══════════════════════════════════════════════════════════════════════════

console.log("=== Test 1: extractLessons with artifact JSON ===");
{
  const artifactJson = JSON.stringify({
    type: "artifact",
    summary: "研究完成，發現三個關鍵洞察",
    outputs: [
      { type: "finding", content: "第一個發現：系統延遲主要來自 DNS lookup 過慢導致每次請求多花 200ms" },
      { type: "recommendation", content: "建議：啟用 DNS cache 可降低 80% 延遲，實測 p99 從 400ms 降到 80ms" },
      { type: "code_change", content: "這個不應該被收錄因為 type 不對" },
      { type: "finding", content: "太短" },  // content <= 20，不收錄
    ],
    files_modified: ["src/dns.ts"],
    tags: ["performance"],
  });
  const rawOutput = `以下是研究結果：\n\n\`\`\`json\n${artifactJson}\n\`\`\`\n\n以上。`;
  const lessons = extractLessons(rawOutput, "研究 DNS 效能");

  assert(lessons.length === 3, `artifact path: got ${lessons.length} lessons (expect 3)`);
  assert(lessons[0] === "研究完成，發現三個關鍵洞察", `summary captured: "${lessons[0]?.slice(0, 20)}..."`);
  assert(lessons[1]?.includes("DNS lookup"), `finding captured: "${lessons[1]?.slice(0, 30)}..."`);
  assert(lessons[2]?.includes("DNS cache"), `recommendation captured: "${lessons[2]?.slice(0, 30)}..."`);
}

// ═══════════════════════════════════════════════════════════════════════════
// Test 2: extractLessons — 無 artifact，fallback 摘要
// ═══════════════════════════════════════════════════════════════════════════

console.log("\n=== Test 2: extractLessons fallback (no artifact) ===");
{
  const longText = "這是一段超過 100 字的普通回覆，".repeat(10) + "結論是應該用 Redis 取代 polling。";
  const lessons = extractLessons(longText, "評估快取方案");

  assert(lessons.length === 1, `fallback path: got ${lessons.length} lesson (expect 1)`);
  assert(lessons[0]?.startsWith("[auto-summary]"), `starts with [auto-summary]`);
  assert(lessons[0]?.length <= 315, `truncated to ≤315 chars (got ${lessons[0]?.length})`);
}

// ═══════════════════════════════════════════════════════════════════════════
// Test 2b: extractLessons — 太短回空
// ═══════════════════════════════════════════════════════════════════════════

console.log("\n=== Test 2b: extractLessons empty for short input ===");
{
  const lessons = extractLessons("OK", "micro task");
  assert(lessons.length === 0, `short input returns empty (got ${lessons.length})`);
}

// ═══════════════════════════════════════════════════════════════════════════
// Test 3: appendMemory + readMemory round-trip
// ═══════════════════════════════════════════════════════════════════════════

console.log("\n=== Test 3: appendMemory + readMemory round-trip ===");
{
  cleanup(); // 確保乾淨狀態

  await appendMemory(TEST_NAME, "goal-alpha", ["lesson 1", "lesson 2"]);
  const mem1 = await readMemory(TEST_NAME);
  assert(mem1.includes("lesson 1"), "lesson 1 persisted");
  assert(mem1.includes("lesson 2"), "lesson 2 persisted");
  assert(mem1.includes("goal-alpha"), "goal tag present");

  // 追加第二批
  await appendMemory(TEST_NAME, "goal-beta", ["lesson 3"]);

